// CUDA Kernel: Fan1
// Corresponds to OpenCL kernel Fan1
__global__ void Fan1(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalId = blockIdx.x * blockDim.x + threadIdx.x;

    if (globalId < size - 1 - t) {
        // Index calculation: size * (globalId + t + 1) + t
        int row = globalId + t + 1;
        int col = t;
        int idx_m = size * row + col;
        int idx_a_num = size * row + col;
        int idx_a_den = size * t + t;

        m_dev[idx_m] = a_dev[idx_a_num] / a_dev[idx_a_den];
    }
}

// CUDA Kernel: Fan2
// Corresponds to OpenCL kernel Fan2
__global__ void Fan2(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalIdx = blockIdx.x * blockDim.x + threadIdx.x;
    int globalIdy = blockIdx.y * blockDim.y + threadIdx.y;

    if (globalIdx < size - 1 - t && globalIdy < size - t) {
        int row_a = globalIdx + 1 + t;
        int col_a = globalIdy + t;
        int idx_a_target = size * row_a + col_a;

        int row_m = globalIdx + 1 + t;
        int col_m = t;
        int idx_m = size * row_m + col_m;

        int row_a_src = t;
        int col_a_src = globalIdy + t;
        int idx_a_src = size * row_a_src + col_a_src;

        a_dev[idx_a_target] -= m_dev[idx_m] * a_dev[idx_a_src];

        if (globalIdy == 0) {
            int idx_b_target = globalIdx + 1 + t;
            int idx_b_src = t;
            // Note: In the source OpenCL code, the index for m_dev here uses (globalIdy+t) which is t since globalIdy==0
            // m_dev[size*(globalIdx+1+t)+(globalIdy+t)] -> m_dev[size*(globalIdx+1+t)+t]
            b_dev[idx_b_target] -= m_dev[idx_m] * b_dev[idx_b_src];
        }
    }
}

// Helper for timeval subtraction
void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *result) {
    result->tv_sec = t1->tv_sec - t2->tv_sec;
    result->tv_usec = t1->tv_usec - t2->tv_usec;
    if (result->tv_usec < 0) {
        result->tv_sec--;
        result->tv_usec += 1000000;
    }
}

// Host functions to mimic the behavior of the original C code
void InitMat(FILE *fp, int size, float *ary, int nrow, int ncol) {
    int i, j;
    for (i = 0; i < nrow; i++) {
        for (j = 0; j < ncol; j++) {
            fscanf(fp, "%f", &ary[size * i + j]);
        }
    }
}

void InitAry(FILE *fp, float *ary, int ary_size) {
    int i;
    for (i = 0; i < ary_size; i++) {
        fscanf(fp, "%f", &ary[i]);
    }
}

void PrintMat(float *ary, int size, int nrow, int ncol) {
    int i, j;
    for (i = 0; i < nrow; i++) {
        for (j = 0; j < ncol; j++) {
            printf("%8.2f ", ary[size * i + j]);
        }
        printf("\n");
    }
    printf("\n");
}

void PrintAry(float *ary, int ary_size) {
    int i;
    for (i = 0; i < ary_size; i++) {
        printf("%.2f ", ary[i]);
    }
    printf("\n");
}

void InitPerRun(int size, float *m) {
    int i;
    for (i = 0; i < size * size; i++) {
        m[i] = 0.0f;
    }
}

void BackSub(float *a, float *b, float *finalVec, int size) {
    int i, j;
    for (i = 0; i < size; i++) {
        finalVec[size - i - 1] = b[size - i - 1];
        for (j = 0; j < i; j++) {
            finalVec[size - i - 1] -= a[size * (size - i - 1) + (size - j - 1)] * finalVec[size - j - 1];
        }
        finalVec[size - i - 1] = finalVec[size - i - 1] / a[size * (size - i - 1) + (size - i - 1)];
    }
}

int parseCommandline(int argc, char *argv[], char* filename,
                     int *q, int *v, int *t_flag, int *p, int *d, int *size) {
    int i;
    if (argc < 2) return 1;
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 's':
                    i++;
                    *size = atoi(argv[i]);
                    printf("Create matrix internally in parse, size = %d \n", *size);
                    break;
                case 'f':
                    i++;
                    strncpy(filename, argv[i], 100);
                    printf("Read file from %s \n", filename);
                    break;
                case 'h':
                    return 1;
                    break;
                case 'q':
                    *q = 1;
                    break;
                case 'v':
                    *v = 1;
                    break;
                case 't':
                    *t_flag = 1;
                    break;
                case 'p':
                    i++;
                    *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    *d = atoi(argv[i]);
                    break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

