void ForwardSub(float *a, float *b, float *m, int size, int timing) {
    float *d_a, *d_b, *d_m;
    size_t bytes_a = size * size * sizeof(float);
    size_t bytes_b = size * sizeof(float);
    size_t bytes_m = size * size * sizeof(float);
    float writeMB = 0, readMB = 0;

    gettimeofday(&tv_mem_alloc_start, NULL);

    // Allocate device memory
    CUDA_ERR_CHECK(cudaMalloc((void**)&d_a, bytes_a));
    CUDA_ERR_CHECK(cudaMalloc((void**)&d_b, bytes_b));
    CUDA_ERR_CHECK(cudaMalloc((void**)&d_m, bytes_m));

    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    // Copy input data to device
    gettimeofday(&tv_h2d_start, NULL);
    CUDA_ERR_CHECK(cudaMemcpy(d_a, a, bytes_a, cudaMemcpyHostToDevice));
    CUDA_ERR_CHECK(cudaMemcpy(d_b, b, bytes_b, cudaMemcpyHostToDevice));
    CUDA_ERR_CHECK(cudaMemcpy(d_m, m, bytes_m, cudaMemcpyHostToDevice));
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    writeMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);

    // Define block and grid sizes
    // Fan1 is 1D
    dim3 block1(256);
    dim3 grid1((size + block1.x - 1) / block1.x);

    // Fan2 is 2D
    dim3 block2(16, 16);
    dim3 grid2((size + block2.x - 1) / block2.x, (size + block2.y - 1) / block2.y);

    int t;
    gettimeofday(&tv_kernel_start, NULL);

    for (t = 0; t < (size - 1); t++) {
        // Launch Fan1
        Fan1<<<grid1, block1>>>(d_m, d_a, d_b, size, t);
        CUDA_ERR_CHECK(cudaGetLastError());

        // Launch Fan2
        Fan2<<<grid2, block2>>>(d_m, d_a, d_b, size, t);
        CUDA_ERR_CHECK(cudaGetLastError());
    }

    // Wait for completion
    CUDA_ERR_CHECK(cudaDeviceSynchronize());

    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    // Copy results back to host
    gettimeofday(&tv_d2h_start, NULL);
    CUDA_ERR_CHECK(cudaMemcpy(a, d_a, bytes_a, cudaMemcpyDeviceToHost));
    CUDA_ERR_CHECK(cudaMemcpy(b, d_b, bytes_b, cudaMemcpyDeviceToHost));
    CUDA_ERR_CHECK(cudaMemcpy(m, d_m, bytes_m, cudaMemcpyDeviceToHost));
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    readMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);

    if (timing) {
        printf("Matrix Size\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
        printf("%dx%d      \t",size,size);
        printf("%f [%.2fMB]\t",h2d_time,writeMB);
        printf("%f\t",kernel_time);
        printf("%f [%.2fMB]\t",d2h_time,readMB);
        printf("%f\n\n",h2d_time+kernel_time+d2h_time);
    }

    // Free device memory
    gettimeofday(&tv_close_start, NULL);
    cudaFree(d_a);
    cudaFree(d_b);
    cudaFree(d_m);
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
}

int main(int argc, char *argv[]) {
    float *a = NULL, *b = NULL, *finalVec = NULL;
    float *m = NULL;
    int size = -1;
    FILE *fp;
    char filename[200];
    int show_data = 0, quiet = 0, timing = 0, platform = 0, device = 0;

    if (parseCommandline(argc, argv, filename,
                         &quiet, &show_data, &timing, &platform, &device, &size)) {
        printUsage();
        return 0;
    }

    gettimeofday(&tv_total_start, NULL);

    if (size < 1) {
        fp = fopen(filename, "r");
        if (!fp) {
            printf("Error opening file: %s\n", filename);
            return -1;
        }
        fscanf(fp, "%d", &size);

        a = (float *)malloc(size * size * sizeof(float));
        InitMat(fp, size, a, size, size);

        b = (float *)malloc(size * sizeof(float));
        InitAry(fp, b, size);

        fclose(fp);
    } else {
        printf("create input internally before create, size = %d \n", size);
        a = (float *)malloc(size * size * sizeof(float));
        // Simple initialization for internal generation if needed
        for(int i=0; i<size*size; i++) a[i] = 1.0f; 

        b = (float *)malloc(size * sizeof(float));
        for (int i = 0; i < size; i++)
            b[i] = 1.0f;
    }

    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    if (!quiet && show_data) {
        printf("The input matrix a is:\n");
        PrintMat(a, size, size, size);

        printf("The input array b is:\n");
        PrintAry(b, size);
    }

    m = (float *)malloc(size * size * sizeof(float));
    finalVec = (float *)malloc(size * sizeof(float));

    InitPerRun(size, m);

    ForwardSub(a, b, m, size, timing);

    if (!quiet && show_data) {
        printf("The result of matrix m is: \n");
        PrintMat(m, size, size, size);
        printf("The result of matrix a is: \n");
        PrintMat(a, size, size, size);
        printf("The result of array b is: \n");
        PrintAry(b, size);

        BackSub(a, b, finalVec, size);
        printf("The final solution is: \n");
        PrintAry(finalVec, size);
    }

    free(m);
    free(a);
    free(b);
    free(finalVec);

    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    if (timing) {
        printf("Init: %f\n", init_time);
        printf("MemAlloc: %f\n", mem_alloc_time);
        printf("HtoD: %f\n", h2d_time);
        printf("Exec: %f\n", kernel_time);
        printf("DtoH: %f\n", d2h_time);
        printf("Close: %f\n", close_time);
        printf("Total: %f\n", total_time);
    }

    return 0;
}
